def calculate_lott_vote_percentages():
    elections = {
        "1994 European Parliament (Northumbria)": 4.2,
        "1997 General Election (Hexham)": 2.5,
        "2001 General Election (Isle of Wight)": 3.3
    }
    return elections

# Example usage
vote_percentages = calculate_lott_vote_percentages()
for election, percentage in vote_percentages.items():
    print(f"{election}: {percentage}%")

This function returns a dictionary of the vote percentages David Lott received in the specified elections.
